// Backend factory implementation.

#include "backend_factory.h"
#include "gguf_inspect.h"

#include "qwen35_backend.h"
#include "qwen35moe_backend.h"
#include "laguna_backend.h"
#include "laguna_layer_split_adapter.h"
#include "qwen3_backend.h"
#include "gemma4_backend.h"
#include "gemma4_layer_split_adapter.h"
#include "layer_split_backend.h"
#include "qwen35_layer_split_adapter.h"

#include <cstdio>
#include <algorithm>

namespace dflash::common {

std::string detect_arch(const char * model_path) {
    auto info = inspect_gguf_model_info(model_path);
    return info.arch;
}

bool arch_supports_remote_draft(const std::string & arch) {
    return arch == "qwen35";
}

bool arch_supports_pflash_compression(const std::string & arch) {
    return arch == "qwen35" || arch == "qwen3" || arch == "qwen35moe";
}

std::unique_ptr<ModelBackend> create_backend(const BackendArgs & args) {
    if (!args.model_path) {
        std::fprintf(stderr, "[backend_factory] model_path is null\n");
        return nullptr;
    }

    const std::string arch = detect_arch(args.model_path);
    if (arch.empty()) {
        std::fprintf(stderr, "[backend_factory] failed to detect architecture from %s\n",
                     args.model_path);
        return nullptr;
    }

    std::fprintf(stderr, "[backend_factory] detected arch=%s\n", arch.c_str());

    if (arch == "qwen35") {
        if (args.device.is_layer_split()) {
            Qwen35LayerSplitAdapterConfig cfg;
            cfg.target_path        = args.model_path;
            cfg.draft_path         = args.draft_path;
            cfg.device             = args.device;
            cfg.draft_gpu          = args.draft_device.gpu;
            cfg.remote_draft       = args.remote_draft;
            cfg.remote_target_shard = args.remote_target_shard;
            cfg.fa_window          = args.fa_window;
            cfg.kq_stride_pad      = args.kq_stride_pad;
            cfg.draft_swa_window   = args.draft_swa_window;
            cfg.draft_ctx_max      = args.draft_ctx_max;
            cfg.chunk              = args.chunk;
            cfg.max_verify_tokens  = args.ddtree_mode
                ? std::max<int>(DFLASH27B_DRAFT_BLOCK_SIZE, args.ddtree_budget + 1)
                : DFLASH27B_DRAFT_BLOCK_SIZE;
            cfg.run_dflash         = args.draft_path != nullptr;

            auto adapter = std::make_unique<Qwen35LayerSplitAdapter>(cfg);
            auto backend = std::make_unique<LayerSplitBackend>(std::move(adapter));
            if (!backend->init()) {
                std::fprintf(stderr, "[backend_factory] LayerSplitBackend(qwen35) init failed\n");
                return nullptr;
            }
            return backend;
        }

        Qwen35Config cfg;
        cfg.target_path        = args.model_path;
        cfg.draft_path         = args.draft_path;
        cfg.device             = args.device;
        cfg.draft_gpu          = args.draft_device.gpu;
        cfg.remote_draft       = args.remote_draft;
        cfg.stream_fd          = args.stream_fd;
        cfg.fa_window          = args.fa_window;
        cfg.kq_stride_pad      = args.kq_stride_pad;
        cfg.draft_swa_window   = args.draft_swa_window;
        cfg.draft_ctx_max      = args.draft_ctx_max;
        cfg.fast_rollback      = args.fast_rollback;
        cfg.seq_verify         = args.seq_verify;
        cfg.ddtree_mode        = args.ddtree_mode;
        cfg.ddtree_budget      = args.ddtree_budget;
        cfg.ddtree_temp        = args.ddtree_temp;
        cfg.ddtree_chain_seed  = args.ddtree_chain_seed;
        cfg.use_feature_mirror = args.use_feature_mirror;

        auto backend = std::make_unique<Qwen35Backend>(cfg);
        if (!backend->init()) {
            std::fprintf(stderr, "[backend_factory] Qwen35Backend init failed\n");
            return nullptr;
        }
        return backend;

    } else if (arch == "qwen35moe") {
        Qwen35Config cfg;
        cfg.target_path        = args.model_path;
        cfg.draft_path         = args.draft_path;
        cfg.device             = args.device;
        cfg.draft_gpu          = args.draft_device.gpu;
        cfg.stream_fd          = args.stream_fd;
        cfg.fa_window          = args.fa_window;
        cfg.kq_stride_pad      = args.kq_stride_pad;
        cfg.draft_swa_window   = args.draft_swa_window;
        cfg.draft_ctx_max      = args.draft_ctx_max;
        cfg.fast_rollback      = args.fast_rollback;
        cfg.seq_verify         = args.seq_verify;
        cfg.ddtree_mode        = args.ddtree_mode;
        cfg.ddtree_budget      = args.ddtree_budget;
        cfg.ddtree_temp        = args.ddtree_temp;
        cfg.ddtree_chain_seed  = args.ddtree_chain_seed;
        cfg.use_feature_mirror = args.use_feature_mirror;

        auto backend = std::make_unique<Qwen35MoeBackend>(cfg);
        if (!backend->init()) {
            std::fprintf(stderr, "[backend_factory] Qwen35MoeBackend init failed\n");
            return nullptr;
        }
        return backend;

    } else if (arch == "laguna") {
        if (args.device.is_layer_split()) {
            LagunaLayerSplitAdapterConfig cfg;
            cfg.target_path = args.model_path;
            cfg.device      = args.device;
            cfg.remote_target_shard = args.remote_target_shard;
            cfg.chunk       = args.chunk;

            auto adapter = std::make_unique<LagunaLayerSplitAdapter>(cfg);
            auto backend = std::make_unique<LayerSplitBackend>(std::move(adapter));
            if (!backend->init()) {
                std::fprintf(stderr, "[backend_factory] LayerSplitBackend(laguna) init failed\n");
                return nullptr;
            }
            return backend;
        }

        LagunaBackendArgs lcfg;
        lcfg.target_path = args.model_path;
        lcfg.device      = args.device;
        lcfg.max_ctx     = args.device.max_ctx;
        lcfg.chunk       = args.chunk;
        // kv_type defaults to Q8_0 in LagunaBackendArgs

        auto backend = std::make_unique<LagunaBackend>(lcfg);
        if (!backend->init()) {
            std::fprintf(stderr, "[backend_factory] LagunaBackend init failed\n");
            return nullptr;
        }
        return backend;

    } else if (arch == "qwen3") {
        Qwen3BackendConfig qcfg;
        qcfg.model_path = args.model_path;
        qcfg.device     = args.device;
        qcfg.stream_fd  = args.stream_fd;
        qcfg.chunk      = args.chunk;

        auto backend = std::make_unique<Qwen3Backend>(qcfg);
        if (!backend->init()) {
            std::fprintf(stderr, "[backend_factory] Qwen3Backend init failed\n");
            return nullptr;
        }
        return backend;

    } else if (arch == "gemma4") {
        if (args.device.is_layer_split()) {
            Gemma4LayerSplitAdapterConfig cfg;
            cfg.target_path = args.model_path;
            cfg.device      = args.device;
            cfg.remote_target_shard = args.remote_target_shard;
            cfg.chunk       = args.chunk;
            cfg.fa_window   = args.fa_window;

            auto adapter = std::make_unique<Gemma4LayerSplitAdapter>(cfg);
            auto backend = std::make_unique<LayerSplitBackend>(std::move(adapter));
            if (!backend->init()) {
                std::fprintf(stderr, "[backend_factory] LayerSplitBackend(gemma4) init failed\n");
                return nullptr;
            }
            return backend;
        }

        Gemma4BackendConfig gcfg;
        gcfg.model_path    = args.model_path;
        gcfg.draft_path    = args.draft_path;
        gcfg.draft_gpu     = args.draft_device.gpu;
        gcfg.draft_ctx_max = args.draft_ctx_max;
        gcfg.device        = args.device;
        gcfg.stream_fd     = args.stream_fd;
        gcfg.chunk         = args.chunk;

        auto backend = std::make_unique<Gemma4Backend>(gcfg);
        if (!backend->init()) {
            std::fprintf(stderr, "[backend_factory] Gemma4Backend init failed\n");
            return nullptr;
        }
        return backend;

    } else {
        std::fprintf(stderr, "[backend_factory] unsupported architecture: %s\n",
                     arch.c_str());
        return nullptr;
    }
}

}  // namespace dflash::common

// backend_ipc.cpp - generic backend IPC process launcher.

#include "backend_ipc.h"
#include "io_utils.h"

#include <cstdint>
#include <cstring>
#include <cstdio>
#include <cstdlib>
#include <string>
#include <vector>

#if !defined(_WIN32)
#  include <cerrno>
#  include <fcntl.h>
#  include <sys/mman.h>
#  include <sys/stat.h>
#  include <sys/wait.h>
#  if defined(__linux__)
#    include <sys/syscall.h>
#  endif
#  include <unistd.h>
#endif

namespace dflash::common {

const char * backend_ipc_mode_name(BackendIpcMode mode) {
    switch (mode) {
        case BackendIpcMode::Invalid: return "invalid";
        case BackendIpcMode::DFlashDraft: return "dflash-draft";
        case BackendIpcMode::PFlashCompress: return "pflash-compress";
        case BackendIpcMode::Qwen35TargetShard: return "qwen35-target-shard";
        case BackendIpcMode::Gemma4TargetShard: return "gemma4-target-shard";
        case BackendIpcMode::LagunaTargetShard: return "laguna-target-shard";
    }
    return "unknown";
}

bool parse_backend_ipc_mode(const std::string & value, BackendIpcMode & out) {
    if (value == "dflash-draft") {
        out = BackendIpcMode::DFlashDraft;
        return true;
    }
    if (value == "pflash-compress") {
        out = BackendIpcMode::PFlashCompress;
        return true;
    }
    if (value == "qwen35-target-shard") {
        out = BackendIpcMode::Qwen35TargetShard;
        return true;
    }
    if (value == "gemma4-target-shard") {
        out = BackendIpcMode::Gemma4TargetShard;
        return true;
    }
    if (value == "laguna-target-shard") {
        out = BackendIpcMode::LagunaTargetShard;
        return true;
    }
    return false;
}

const char * backend_ipc_payload_transport_name(BackendIpcPayloadTransport transport) {
    switch (transport) {
        case BackendIpcPayloadTransport::Stream: return "stream";
        case BackendIpcPayloadTransport::Shared: return "shared";
        case BackendIpcPayloadTransport::Auto: return "auto";
    }
    return "unknown";
}

bool parse_backend_ipc_payload_transport(const std::string & value,
                                         BackendIpcPayloadTransport & out) {
    if (value == "stream") {
        out = BackendIpcPayloadTransport::Stream;
        return true;
    }
    if (value == "shared") {
        out = BackendIpcPayloadTransport::Shared;
        return true;
    }
    if (value == "auto") {
        out = BackendIpcPayloadTransport::Auto;
        return true;
    }
    return false;
}

bool BackendIpcProcess::start(const BackendIpcLaunchConfig & cfg) {
#if defined(_WIN32)
    (void)cfg;
    std::fprintf(stderr, "Backend IPC is only implemented on POSIX hosts\n");
    return false;
#else
    close();
    if (cfg.bin.empty() || cfg.payload_path.empty()) return false;
    if (!init_work_dir(cfg.work_dir)) return false;

    int cmd_pipe[2] = {-1, -1};
    int payload_pipe[2] = {-1, -1};
    int stream_pipe[2] = {-1, -1};
    if (::pipe(cmd_pipe) != 0 || ::pipe(payload_pipe) != 0 || ::pipe(stream_pipe) != 0) {
        std::fprintf(stderr, "backend-ipc pipe failed: %s\n", std::strerror(errno));
        if (cmd_pipe[0] >= 0) ::close(cmd_pipe[0]);
        if (cmd_pipe[1] >= 0) ::close(cmd_pipe[1]);
        if (payload_pipe[0] >= 0) ::close(payload_pipe[0]);
        if (payload_pipe[1] >= 0) ::close(payload_pipe[1]);
        if (stream_pipe[0] >= 0) ::close(stream_pipe[0]);
        if (stream_pipe[1] >= 0) ::close(stream_pipe[1]);
        return false;
    }
    const bool shared_required =
        cfg.payload_transport == BackendIpcPayloadTransport::Shared;
    const bool shared_requested =
        shared_required || cfg.payload_transport == BackendIpcPayloadTransport::Auto;
    if (cfg.payload_transport == BackendIpcPayloadTransport::Shared &&
        cfg.shared_payload_bytes == 0) {
        std::fprintf(stderr, "backend-ipc shared payload requested with zero capacity\n");
        ::close(cmd_pipe[0]); ::close(cmd_pipe[1]);
        ::close(payload_pipe[0]); ::close(payload_pipe[1]);
        ::close(stream_pipe[0]); ::close(stream_pipe[1]);
        return false;
    }
    if (shared_requested && cfg.shared_payload_bytes > 0) {
        if (!init_shared_payload(cfg.shared_payload_bytes)) {
            if (shared_required) {
                close();
                ::close(cmd_pipe[0]); ::close(cmd_pipe[1]);
                ::close(payload_pipe[0]); ::close(payload_pipe[1]);
                ::close(stream_pipe[0]); ::close(stream_pipe[1]);
                return false;
            }
            std::fprintf(stderr,
                         "backend-ipc auto shared payload unavailable; using stream\n");
        }
    }
    resolved_payload_transport_ = has_shared_payload()
        ? BackendIpcPayloadTransport::Shared
        : BackendIpcPayloadTransport::Stream;

    pid_ = ::fork();
    if (pid_ < 0) {
        std::fprintf(stderr, "backend-ipc fork failed: %s\n", std::strerror(errno));
        ::close(cmd_pipe[0]); ::close(cmd_pipe[1]);
        ::close(payload_pipe[0]); ::close(payload_pipe[1]);
        ::close(stream_pipe[0]); ::close(stream_pipe[1]);
        close();
        pid_ = -1;
        return false;
    }
    if (pid_ == 0) {
        if (cmd_pipe[0] != STDIN_FILENO && ::dup2(cmd_pipe[0], STDIN_FILENO) < 0) {
            std::fprintf(stderr, "backend-ipc dup2 failed: %s\n", std::strerror(errno));
            _exit(127);
        }
        if (cmd_pipe[0] != STDIN_FILENO) ::close(cmd_pipe[0]);
        ::close(cmd_pipe[1]);
        ::close(payload_pipe[1]);
        ::close(stream_pipe[0]);

        std::vector<std::string> argv_storage;
        argv_storage.reserve(cfg.args.size() + 6);
        argv_storage.emplace_back(cfg.bin);
        argv_storage.emplace_back(
            std::string("--backend-ipc-mode=") + backend_ipc_mode_name(cfg.mode));
        argv_storage.emplace_back(cfg.payload_path);
        for (const std::string & arg : cfg.args) argv_storage.emplace_back(arg);
        argv_storage.emplace_back("--payload-fd=" + std::to_string(payload_pipe[0]));
        if (has_shared_payload()) {
            argv_storage.emplace_back("--shared-payload-fd=" +
                                      std::to_string(shared_payload_fd_));
            argv_storage.emplace_back("--shared-payload-bytes=" +
                                      std::to_string(shared_payload_capacity_));
        }
        argv_storage.emplace_back("--stream-fd=" + std::to_string(stream_pipe[1]));

        std::vector<char *> argv;
        argv.reserve(argv_storage.size() + 1);
        for (std::string & arg : argv_storage) argv.push_back(arg.data());
        argv.push_back(nullptr);
        ::execv(cfg.bin.c_str(), argv.data());
        std::fprintf(stderr, "backend-ipc exec failed: %s: %s\n",
                     cfg.bin.c_str(), std::strerror(errno));
        _exit(127);
    }

    ::close(cmd_pipe[0]);
    ::close(payload_pipe[0]);
    ::close(stream_pipe[1]);
    payload_fd_ = payload_pipe[1];
    stream_fd_ = stream_pipe[0];
    cmd_ = ::fdopen(cmd_pipe[1], "w");
    if (!cmd_) {
        std::fprintf(stderr, "backend-ipc fdopen failed: %s\n", std::strerror(errno));
        ::close(cmd_pipe[1]);
        close();
        return false;
    }
    int32_t status = -1;
    if (!read_exact_fd(stream_fd_, &status, sizeof(status)) || status != 0) {
        std::fprintf(stderr, "backend-ipc daemon did not become ready (status=%d)\n", status);
        close();
        return false;
    }
    active_ = true;
    std::printf("[backend-ipc] ready mode=%s payload_transport=%s bin=%s work_dir=%s\n",
                backend_ipc_mode_name(cfg.mode),
                backend_ipc_payload_transport_name(resolved_payload_transport_),
                cfg.bin.c_str(), work_dir_.c_str());
    return true;
#endif
}

void BackendIpcProcess::close() {
#if !defined(_WIN32)
    if (cmd_) {
        std::fclose(cmd_);
        cmd_ = nullptr;
    }
    if (stream_fd_ >= 0) {
        ::close(stream_fd_);
        stream_fd_ = -1;
    }
    if (payload_fd_ >= 0) {
        ::close(payload_fd_);
        payload_fd_ = -1;
    }
    if (shared_payload_map_) {
        ::munmap(shared_payload_map_, shared_payload_bytes_);
        shared_payload_map_ = nullptr;
    }
    if (shared_payload_fd_ >= 0) {
        ::close(shared_payload_fd_);
        shared_payload_fd_ = -1;
    }
    if (pid_ > 0) {
        int status = 0;
        ::waitpid(pid_, &status, 0);
        pid_ = -1;
    }
    if (owns_work_dir_ && !work_dir_.empty()) {
        ::rmdir(work_dir_.c_str());
    }
#endif
    active_ = false;
    owns_work_dir_ = false;
    shared_payload_bytes_ = 0;
    shared_payload_capacity_ = 0;
    shared_payload_seq_ = 0;
    resolved_payload_transport_ = BackendIpcPayloadTransport::Stream;
    work_dir_.clear();
    seq_ = 0;
}

std::string BackendIpcProcess::next_path(const char * prefix) {
    return work_dir_ + "/" + prefix + "_" + std::to_string(seq_++) + ".bin";
}

bool BackendIpcProcess::write_shared_payload(const void * data, size_t bytes, uint64_t & seq) {
    if (!shared_payload_map_ || bytes > shared_payload_capacity_) return false;
    if (bytes > 0 && !data) return false;
    auto * header = static_cast<BackendIpcSharedPayloadHeader *>(shared_payload_map_);
    void * payload = static_cast<void *>(
        static_cast<char *>(shared_payload_map_) + backend_ipc_shared_payload_header_bytes());
    if (bytes > 0) {
        std::memcpy(payload, data, bytes);
    }
    seq = ++shared_payload_seq_;
    header->bytes = (uint64_t)bytes;
    header->sequence = seq;
    return true;
}

#if !defined(_WIN32)
bool BackendIpcProcess::init_shared_payload(size_t bytes) {
    if (bytes == 0) return false;
    size_t map_bytes = 0;
    if (!backend_ipc_shared_payload_map_bytes(bytes, map_bytes)) return false;
    int fd = -1;
#  if defined(__linux__) && defined(SYS_memfd_create)
    fd = (int)::syscall(SYS_memfd_create, "backend-ipc-payload", 0);
#  endif
    if (fd < 0) {
        const char * tmp = std::getenv("TMPDIR");
        std::string templ = std::string(tmp && *tmp ? tmp : "/tmp") +
                            "/backend-ipc-payload-XXXXXX";
        std::vector<char> templ_buf(templ.begin(), templ.end());
        templ_buf.push_back('\0');
        fd = ::mkstemp(templ_buf.data());
        if (fd >= 0) {
            ::unlink(templ_buf.data());
        }
    }
    if (fd < 0) {
        std::fprintf(stderr, "backend-ipc shared payload fd failed: %s\n",
                     std::strerror(errno));
        return false;
    }
    if (::ftruncate(fd, (off_t)map_bytes) != 0) {
        std::fprintf(stderr, "backend-ipc shared payload truncate failed: %s\n",
                     std::strerror(errno));
        ::close(fd);
        return false;
    }
    void * mapped = ::mmap(nullptr, map_bytes, PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    if (mapped == MAP_FAILED) {
        std::fprintf(stderr, "backend-ipc shared payload mmap failed: %s\n",
                     std::strerror(errno));
        ::close(fd);
        return false;
    }
    std::memset(mapped, 0, map_bytes);
    shared_payload_fd_ = fd;
    shared_payload_map_ = mapped;
    shared_payload_bytes_ = map_bytes;
    shared_payload_capacity_ = bytes;
    return true;
}

bool BackendIpcProcess::init_work_dir(const std::string & requested) {
    if (!requested.empty()) {
        work_dir_ = requested;
        owns_work_dir_ = false;
        if (::mkdir(work_dir_.c_str(), 0700) != 0) {
            if (errno != EEXIST) {
                std::fprintf(stderr, "backend-ipc mkdir failed: %s: %s\n",
                             work_dir_.c_str(), std::strerror(errno));
                return false;
            }
            struct stat st;
            if (::stat(work_dir_.c_str(), &st) != 0 || !S_ISDIR(st.st_mode)) {
                std::fprintf(stderr, "backend-ipc work_dir is not a directory: %s\n",
                             work_dir_.c_str());
                return false;
            }
        }
        return true;
    }
    const char * tmp = std::getenv("TMPDIR");
    std::string templ = std::string(tmp && *tmp ? tmp : "/tmp") +
                        "/backend-ipc-XXXXXX";
    std::vector<char> buf(templ.begin(), templ.end());
    buf.push_back('\0');
    char * dir = ::mkdtemp(buf.data());
    if (!dir) {
        std::fprintf(stderr, "backend-ipc mkdtemp failed: %s\n", std::strerror(errno));
        return false;
    }
    work_dir_ = dir;
    owns_work_dir_ = true;
    return true;
}
#endif

}  // namespace dflash::common

#include "backend_precision.h"

#if defined(DFLASH27B_BACKEND_CUDA) || defined(DFLASH27B_BACKEND_HIP) || defined(GGML_USE_HIP)
#include "gpu_runtime_compat.h"
#endif

#include <cctype>
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <string>
#include <vector>

namespace dflash::common {
namespace {

std::string backend_device_description(ggml_backend_t backend) {
    if (!backend) {
        return {};
    }
    ggml_backend_dev_t dev = ggml_backend_get_device(backend);
    if (!dev) {
        return {};
    }
    const char * desc = ggml_backend_dev_description(dev);
    if (desc && desc[0]) {
        return desc;
    }
    return {};
}

std::string backend_device_logical_name(ggml_backend_t backend) {
    if (!backend) {
        return {};
    }
    ggml_backend_dev_t dev = ggml_backend_get_device(backend);
    if (!dev) {
        return {};
    }
    const char * name = ggml_backend_dev_name(dev);
    return name ? std::string(name) : std::string{};
}

std::string backend_name(ggml_backend_t backend) {
    if (!backend) {
        return {};
    }
    ggml_backend_dev_t dev = ggml_backend_get_device(backend);
    if (!dev) {
        return {};
    }
    ggml_backend_reg_t reg = ggml_backend_dev_backend_reg(dev);
    const char * name = reg ? ggml_backend_reg_name(reg) : nullptr;
    return name ? std::string(name) : std::string{};
}

int parse_backend_device_id(const std::string & logical_name) {
    if (logical_name.empty()) return -1;
    size_t end = logical_name.size();
    while (end > 0 && std::isspace((unsigned char)logical_name[end - 1])) {
        --end;
    }
    size_t begin = end;
    while (begin > 0 && std::isdigit((unsigned char)logical_name[begin - 1])) {
        --begin;
    }
    if (begin == end) return -1;
    return std::atoi(logical_name.substr(begin, end - begin).c_str());
}

int current_device_id() {
#if defined(DFLASH27B_BACKEND_CUDA) || defined(DFLASH27B_BACKEND_HIP) || defined(GGML_USE_HIP)
    int device = -1;
    if (cudaGetDevice(&device) != cudaSuccess || device < 0) {
        return -1;
    }
    return device;
#else
    return -1;
#endif
}

int device_props_for(int device,
                     std::string * device_name,
                     std::string * arch_name) {
#if defined(DFLASH27B_BACKEND_CUDA) || defined(DFLASH27B_BACKEND_HIP) || defined(GGML_USE_HIP)
    if (device < 0) {
        return 0;
    }
    cudaDeviceProp prop{};
    if (cudaGetDeviceProperties(&prop, device) != cudaSuccess) {
        return 0;
    }
    if (device_name && prop.name[0]) {
        *device_name = prop.name;
    }
#if defined(DFLASH27B_BACKEND_HIP) || defined(GGML_USE_HIP)
    if (arch_name && prop.gcnArchName[0]) {
        *arch_name = prop.gcnArchName;
    }
#endif
    return prop.major * 10 + prop.minor;
#else
    (void)device;
    (void)device_name;
    (void)arch_name;
    return 0;
#endif
}

bool arch_starts_with(const std::string & arch, const char * prefix) {
    return arch.compare(0, std::strlen(prefix), prefix) == 0;
}

bool parse_precision_override(const char * env_name, ggml_type & out) {
    if (!env_name || !env_name[0]) return false;
    const char * s = std::getenv(env_name);
    if (!s || !s[0]) return false;
    if (std::strcmp(s, "f32") == 0 || std::strcmp(s, "F32") == 0) {
        out = GGML_TYPE_F32;
        return true;
    }
    if (std::strcmp(s, "f16") == 0 || std::strcmp(s, "F16") == 0) {
        out = GGML_TYPE_F16;
        return true;
    }
    if (std::strcmp(s, "bf16") == 0 || std::strcmp(s, "BF16") == 0) {
        out = GGML_TYPE_BF16;
        return true;
    }
    std::fprintf(stderr, "[precision] ignoring unsupported %s=%s\n", env_name, s);
    return false;
}

void fill_policy_device_info(ggml_backend_t backend,
                             std::string & backend_name_out,
                             std::string & device_name_out,
                             std::string & runtime_arch_out,
                             int & device_id_out,
                             int & cuda_sm_out) {
    backend_name_out = backend_name(backend);
    const std::string logical_name = backend_device_logical_name(backend);
    device_name_out = backend_device_description(backend);
    device_id_out = parse_backend_device_id(logical_name);
    if (device_id_out < 0) {
        device_id_out = current_device_id();
    }
    cuda_sm_out = device_props_for(
        device_id_out,
        device_name_out.empty() ? &device_name_out : nullptr,
        &runtime_arch_out);
    if (backend_name_out.empty()) backend_name_out = "unknown";
    if (device_name_out.empty()) device_name_out = "unknown";
}

} // namespace

const char * backend_precision_type_name(ggml_type type) {
    return ggml_type_name(type);
}

ggml_type select_cuda_backend_precision_type_for_sm(int sm) {
    if (sm >= 80) return GGML_TYPE_BF16;
    if (sm >= 70 || sm == 60) return GGML_TYPE_F16;
    return GGML_TYPE_F32;
}

ggml_type select_hip_activation_precision_type_for_arch(const std::string & arch) {
    if (arch.empty()) return GGML_TYPE_F32;
    if (arch_starts_with(arch, "gfx90a") ||
        arch_starts_with(arch, "gfx94")  ||
        arch_starts_with(arch, "gfx95")  ||
        arch_starts_with(arch, "gfx11")  ||
        arch_starts_with(arch, "gfx12")) {
        return GGML_TYPE_BF16;
    }
    if (arch_starts_with(arch, "gfx9") ||
        arch_starts_with(arch, "gfx10")) {
        return GGML_TYPE_F16;
    }
    return GGML_TYPE_F32;
}

ggml_type combine_activation_precision_types(ggml_type a, ggml_type b) {
    if (a == GGML_TYPE_F32 || b == GGML_TYPE_F32) return GGML_TYPE_F32;
    if (a == GGML_TYPE_F16 || b == GGML_TYPE_F16) return GGML_TYPE_F16;
    if (a == GGML_TYPE_BF16 && b == GGML_TYPE_BF16) return GGML_TYPE_BF16;
    return GGML_TYPE_F32;
}

BackendPrecisionPolicy select_drafter_precision_policy(ggml_backend_t backend) {
    BackendPrecisionPolicy policy;
    fill_policy_device_info(backend, policy.backend_name, policy.device_name,
                            policy.runtime_arch, policy.device_id,
                            policy.cuda_sm);

#if defined(DFLASH27B_BACKEND_CUDA)
    const ggml_type type = select_cuda_backend_precision_type_for_sm(policy.cuda_sm);
    if (type == GGML_TYPE_BF16) {
        policy.weight_type  = GGML_TYPE_BF16;
        policy.compute_type = GGML_TYPE_BF16;
        policy.reason       = "CUDA sm80+ BF16 tensor-core path";
    } else if (type == GGML_TYPE_F16 && policy.cuda_sm >= 70) {
        policy.weight_type  = GGML_TYPE_F16;
        policy.compute_type = GGML_TYPE_F16;
        policy.reason       = "CUDA sm70-sm79 F16 tensor-core path";
    } else if (type == GGML_TYPE_F16) {
        policy.weight_type  = GGML_TYPE_F16;
        policy.compute_type = GGML_TYPE_F16;
        policy.reason       = "CUDA sm60 GP100 F16 path";
    } else {
        policy.weight_type  = GGML_TYPE_F32;
        policy.compute_type = GGML_TYPE_F32;
        policy.reason       = "CUDA legacy compatibility fallback without useful F16/BF16 acceleration";
    }
#elif defined(DFLASH27B_BACKEND_HIP) || defined(GGML_USE_HIP)
    policy.weight_type  = GGML_TYPE_BF16;
    policy.compute_type = GGML_TYPE_BF16;
    policy.reason       = "HIP ROCm/ggml BF16-compatible path";
#else
    policy.weight_type  = GGML_TYPE_F32;
    policy.compute_type = GGML_TYPE_F32;
    policy.reason       = "portable non-GPU fallback";
#endif

    return policy;
}

BackendActivationPolicy select_common_activation_precision_policy(
        const std::vector<ggml_backend_t> & backends,
        bool force_f32,
        const char * override_env) {
    if (backends.empty()) {
        return select_activation_precision_policy(nullptr, force_f32, override_env);
    }

    BackendActivationPolicy policy =
        select_activation_precision_policy(backends.front(), force_f32, override_env);
    ggml_type common_type = policy.activation_type;
    bool mixed = false;
    for (size_t i = 1; i < backends.size(); ++i) {
        const BackendActivationPolicy shard_policy =
            select_activation_precision_policy(backends[i], force_f32, override_env);
        if (shard_policy.activation_type != common_type) {
            mixed = true;
        }
        const ggml_type combined =
            combine_activation_precision_types(common_type, shard_policy.activation_type);
        if (combined != common_type) {
            mixed = true;
        }
        common_type = combined;
    }
    if (mixed) {
        policy.activation_type = common_type;
        policy.backend_name = "mixed";
        policy.device_name = "mixed";
        policy.runtime_arch = "mixed";
        policy.device_id = -1;
        policy.cuda_sm = 0;
        policy.reason = "common shard-compatible activation path";
    }
    return policy;
}

BackendActivationPolicy select_activation_precision_policy(
        ggml_backend_t backend,
        bool force_f32,
        const char * override_env) {
    BackendActivationPolicy policy;
    fill_policy_device_info(backend, policy.backend_name, policy.device_name,
                            policy.runtime_arch, policy.device_id,
                            policy.cuda_sm);

    ggml_type override_type = GGML_TYPE_F32;
    if (!force_f32 && parse_precision_override(override_env, override_type)) {
        policy.activation_type = override_type;
        policy.reason = std::string(override_env) + " override";
        return policy;
    }
    if (force_f32) {
        policy.activation_type = GGML_TYPE_F32;
        policy.reason = "F32 required by capture/IPC feature boundary";
        return policy;
    }

#if defined(DFLASH27B_BACKEND_CUDA)
    policy.activation_type = select_cuda_backend_precision_type_for_sm(policy.cuda_sm);
    if (policy.activation_type == GGML_TYPE_BF16) {
        policy.reason = "CUDA sm80+ BF16 activation path";
    } else if (policy.activation_type == GGML_TYPE_F16 && policy.cuda_sm >= 70) {
        policy.reason = "CUDA sm70-sm79 F16 activation path";
    } else if (policy.activation_type == GGML_TYPE_F16) {
        policy.reason = "CUDA sm60 GP100 F16 activation path";
    } else {
        policy.reason = "CUDA legacy F32 activation fallback";
    }
#elif defined(DFLASH27B_BACKEND_HIP) || defined(GGML_USE_HIP)
    policy.activation_type =
        select_hip_activation_precision_type_for_arch(policy.runtime_arch);
    if (policy.activation_type == GGML_TYPE_BF16) {
        policy.reason = "HIP native BF16 activation path";
    } else if (policy.activation_type == GGML_TYPE_F16) {
        policy.reason = "HIP FP16 activation path";
    } else {
        policy.reason = "HIP legacy F32 activation fallback";
    }
#else
    policy.activation_type = GGML_TYPE_F32;
    policy.reason = "portable F32 activation fallback";
#endif
    return policy;
}

} // namespace dflash::common

// CpuColdFfnCompute: Fused cold expert FFN using ggml vec_dot primitives.
// Bypasses ggml graph dispatch overhead. Uses OpenMP to saturate memory bandwidth.
// Memory-bandwidth bound at ~45 GB/s DDR4. Target: 15.7ms → ~3ms/token.

#include "cold_ffn_compute.h"
#include "ggml-cpu.h"

#include <cmath>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <algorithm>

#ifdef _OPENMP
#include <omp.h>
#endif

namespace dflash::common {

class CpuColdFfnCompute : public ColdFfnCompute {
    int n_ff_max_;
    int n_threads_;

    // Per-thread scratch buffers for parallel down matmul
    struct ThreadBuf {
        std::vector<float> scratch;   // [n_ff * 2] gate_up result + SwiGLU
        std::vector<uint8_t> mid_conv; // down input converted to vec_dot_type
    };
    std::vector<ThreadBuf> thread_bufs_;
    std::vector<uint8_t> inp_conv_;  // input converted (shared, read-only during matmul)

public:
    explicit CpuColdFfnCompute(int n_ff_max, int n_threads = 0) : n_ff_max_(n_ff_max) {
#ifdef _OPENMP
        if (n_threads <= 0) {
            const char * env = std::getenv("DFLASH_COLD_THREADS");
            n_threads = env ? std::atoi(env) : 0;
        }
        n_threads_ = n_threads > 0 ? n_threads : std::min(omp_get_max_threads(), 8);
#else
        n_threads_ = 1;
#endif
        fprintf(stderr, "[cold_ffn] using %d threads\n", n_threads_);
        thread_bufs_.resize(n_threads_);
        for (auto & tb : thread_bufs_) {
            tb.scratch.resize((size_t)n_ff_max * 2);
        }
    }

    void compute(
        const ColdFfnLayer & layer,
        const float * input,
        const int32_t * ids,
        const float * weights,
        int n_cold,
        int n_embd,
        int n_ff,
        float * output) override {

        if (n_cold <= 0) return;
        std::memset(output, 0, sizeof(float) * (size_t)n_embd);

        // Gate/up phase type traits
        const ggml_type gu_type = layer.fused_gate_up ? layer.gate_up_type : layer.gate_type;
        const auto * gu_cpu_traits = ggml_get_type_traits_cpu(gu_type);
        const auto gu_vec_dot = gu_cpu_traits->vec_dot;
        const auto gu_vec_dot_type = gu_cpu_traits->vec_dot_type;
        const auto gu_from_float = ggml_get_type_traits_cpu(gu_vec_dot_type)->from_float;

        // Down phase type traits (may differ from gate/up)
        const auto * dn_cpu_traits = ggml_get_type_traits_cpu(layer.down_type);
        const auto dn_vec_dot = dn_cpu_traits->vec_dot;
        const auto dn_vec_dot_type = dn_cpu_traits->vec_dot_type;
        const auto dn_from_float = ggml_get_type_traits_cpu(dn_vec_dot_type)->from_float;

        const size_t inp_row_size = ggml_row_size(gu_vec_dot_type, n_embd);
        const size_t mid_row_size = ggml_row_size(dn_vec_dot_type, n_ff);
        const size_t gu_weight_row = ggml_row_size(gu_type, n_embd);
        const size_t dn_weight_row = ggml_row_size(layer.down_type, n_ff);

        // For separate gate/up — up may have a different type than gate
        size_t up_weight_row = gu_weight_row;
        const ggml_type up_type_actual = layer.fused_gate_up ? gu_type : layer.up_type;
        (void)up_type_actual;
        ggml_vec_dot_t up_vec_dot = gu_vec_dot;
        ggml_type up_vdt = gu_vec_dot_type;
        if (!layer.fused_gate_up && layer.up_type != layer.gate_type) {
            const auto * up_cpu_traits = ggml_get_type_traits_cpu(layer.up_type);
            up_vec_dot = up_cpu_traits->vec_dot;
            up_vdt = up_cpu_traits->vec_dot_type;
            up_weight_row = ggml_row_size(layer.up_type, n_embd);
        }

        // Ensure input conversion buffer is large enough
        if (inp_conv_.size() < inp_row_size) inp_conv_.resize(inp_row_size);
        // Ensure per-thread mid_conv buffers
        for (auto & tb : thread_bufs_) {
            if (tb.mid_conv.size() < mid_row_size) tb.mid_conv.resize(mid_row_size);
        }

        // Convert input for up if different type
        std::vector<uint8_t> inp_conv_up;
        if (!layer.fused_gate_up && up_vdt != gu_vec_dot_type) {
            size_t up_inp_row_size = ggml_row_size(up_vdt, n_embd);
            inp_conv_up.resize(up_inp_row_size);
            auto up_from_float = ggml_get_type_traits_cpu(up_vdt)->from_float;
            up_from_float(input, inp_conv_up.data(), n_embd);
        }

        // Convert input to gate's vec_dot format once
        gu_from_float(input, inp_conv_.data(), n_embd);

        for (int e = 0; e < n_cold; ++e) {
            const int32_t eid = ids[e];
            const float w = weights[e];
            if (w == 0.0f) continue;

            // Use thread 0's scratch for gate_up (serial phase)
            float * scratch = thread_bufs_[0].scratch.data();

            // ── Phase 1: gate_up matmul → scratch[0..n_ff*2) ──
            // Parallel over rows (each row is independent, reading shared inp_conv_)
            if (layer.fused_gate_up) {
                const char * expert = (const char *)layer.gate_up_data + (size_t)eid * layer.gate_up_stride;
                const int n_rows = n_ff * 2;
#ifdef _OPENMP
                #pragma omp parallel for num_threads(n_threads_) schedule(static)
#endif
                for (int row = 0; row < n_rows; ++row) {
                    const void * row_ptr = expert + (size_t)row * gu_weight_row;
                    gu_vec_dot(n_embd, &scratch[row], 0, row_ptr, 0, inp_conv_.data(), 0, 1);
                }
                if (layer.gate_up_scale != 1.0f) {
                    for (int i = 0; i < n_rows; ++i) scratch[i] *= layer.gate_up_scale;
                }
            } else {
                const char * gate_expert = (const char *)layer.gate_data + (size_t)eid * layer.gate_stride;
                const char * up_expert = (const char *)layer.up_data + (size_t)eid * layer.up_stride;
                const uint8_t * up_inp = (!inp_conv_up.empty()) ? inp_conv_up.data() : inp_conv_.data();
#ifdef _OPENMP
                #pragma omp parallel for num_threads(n_threads_) schedule(static)
#endif
                for (int row = 0; row < n_ff; ++row) {
                    const void * gp = gate_expert + (size_t)row * gu_weight_row;
                    gu_vec_dot(n_embd, &scratch[row], 0, gp, 0, inp_conv_.data(), 0, 1);
                    const void * up = up_expert + (size_t)row * up_weight_row;
                    up_vec_dot(n_embd, &scratch[n_ff + row], 0, up, 0, up_inp, 0, 1);
                }
                if (layer.gate_scale != 1.0f) {
                    for (int i = 0; i < n_ff; ++i) scratch[i] *= layer.gate_scale;
                }
                if (layer.up_scale != 1.0f) {
                    for (int i = 0; i < n_ff; ++i) scratch[n_ff + i] *= layer.up_scale;
                }
            }

            // ── Phase 2: SwiGLU activation ──
            for (int i = 0; i < n_ff; ++i) {
                const float gate = scratch[i];
                const float up = scratch[n_ff + i];
                scratch[i] = (gate / (1.0f + expf(-gate))) * up;
            }

            // ── Phase 3: down matmul → output (weighted accumulate) ──
            // Convert SwiGLU result to down's vec_dot format (serial, small)
            dn_from_float(scratch, thread_bufs_[0].mid_conv.data(), n_ff);
            const uint8_t * mid_conv_data = thread_bufs_[0].mid_conv.data();

            const char * down_expert = (const char *)layer.down_data + (size_t)eid * layer.down_stride;
            const float scale = w * layer.down_scale;

            // Parallel down matmul — each thread accumulates its own output rows
#ifdef _OPENMP
            #pragma omp parallel for num_threads(n_threads_) schedule(static)
#endif
            for (int row = 0; row < n_embd; ++row) {
                float val;
                const void * row_ptr = down_expert + (size_t)row * dn_weight_row;
                dn_vec_dot(n_ff, &val, 0, row_ptr, 0, mid_conv_data, 0, 1);
                output[row] += scale * val;
            }
        }
    }
};

std::unique_ptr<ColdFfnCompute> make_cpu_cold_ffn_compute(int n_ff_max) {
    return std::make_unique<CpuColdFfnCompute>(n_ff_max);
}

