#  include <sys/mman.h>
#  include <unistd.h>
#endif

namespace dflash::common {

namespace {

enum class ProposalResult {
    Ok,
    CommandFailed,
    StreamFailed,
};

}  // namespace

int run_dflash_draft_ipc_daemon(const char * draft_path,
                                int ring_cap,
                                int draft_gpu,
                                int stream_fd,
                                int payload_fd,
                                int shared_payload_fd,
                                size_t shared_payload_bytes) {
#if defined(_WIN32)
    (void)draft_path; (void)ring_cap; (void)draft_gpu; (void)stream_fd;
    (void)payload_fd; (void)shared_payload_fd; (void)shared_payload_bytes;
    std::fprintf(stderr, "DFlash draft IPC daemon is only implemented on POSIX hosts\n");
    return 2;
#else
    if (!draft_path || ring_cap <= 0 || stream_fd < 0) {
        std::fprintf(stderr,
                     "usage: backend_ipc_daemon --backend-ipc-mode=dflash-draft "
                     "<draft> --ring-cap=N --stream-fd=FD [--draft-gpu=N]\n");
        return 2;
    }

    void * shared_payload = nullptr;
    void * shared_payload_data = nullptr;
    size_t shared_payload_capacity = 0;
    size_t shared_payload_map_bytes = 0;
    if (shared_payload_fd >= 0 || shared_payload_bytes > 0) {
        if (shared_payload_fd < 0 || shared_payload_bytes == 0) {
            std::fprintf(stderr, "[draft-ipc-daemon] bad shared payload fd/size\n");
            stream_status(stream_fd, -1);
            return 1;
        }
        if (!backend_ipc_shared_payload_map_bytes(shared_payload_bytes,
                                                  shared_payload_map_bytes)) {
            std::fprintf(stderr, "[draft-ipc-daemon] bad shared payload size\n");
            stream_status(stream_fd, -1);
            return 1;
        }
        shared_payload = ::mmap(nullptr, shared_payload_map_bytes,
                                PROT_READ | PROT_WRITE,
                                MAP_SHARED, shared_payload_fd, 0);
        if (shared_payload == MAP_FAILED) {
            std::fprintf(stderr, "[draft-ipc-daemon] shared payload mmap failed\n");
            stream_status(stream_fd, -1);
            return 1;
        }
        shared_payload_data =
            static_cast<char *>(shared_payload) + backend_ipc_shared_payload_header_bytes();
        shared_payload_capacity = shared_payload_bytes;
    }

    ggml_backend_t backend = ggml_backend_cuda_init(std::max(0, draft_gpu));
    if (!backend) {
        std::fprintf(stderr, "[draft-ipc-daemon] backend init failed gpu=%d\n", draft_gpu);
        stream_status(stream_fd, -1);
        if (shared_payload && shared_payload != MAP_FAILED) {
            ::munmap(shared_payload, shared_payload_map_bytes);
        }
        return 1;
    }

    DraftWeights draft_weights;
    std::string dp(draft_path);
    bool draft_ok = false;
    if (dp.size() >= 5 && dp.substr(dp.size() - 5) == ".gguf") {
        draft_ok = load_draft_gguf(draft_path, backend, draft_weights);
    } else {
        draft_ok = load_draft_safetensors(draft_path, backend, draft_weights);
    }
    if (!draft_ok) {
        std::fprintf(stderr, "[draft-ipc-daemon] draft load failed: %s\n",
                     dflash27b_last_error());
        stream_status(stream_fd, -1);
        ggml_backend_free(backend);
        if (shared_payload && shared_payload != MAP_FAILED) {
            ::munmap(shared_payload, shared_payload_map_bytes);
        }
        return 1;
    }

    DraftFeatureMirror feature_ring;
    if (!draft_feature_mirror_init(feature_ring, backend, draft_gpu, draft_gpu, ring_cap,
                                   draft_weights.n_target_layers, draft_weights.n_embd)) {
        std::fprintf(stderr, "[draft-ipc-daemon] feature ring init failed cap=%d gpu=%d\n",
                     ring_cap, draft_gpu);
        stream_status(stream_fd, -1);
        free_draft_weights(draft_weights);
        ggml_backend_free(backend);
        if (shared_payload && shared_payload != MAP_FAILED) {
            ::munmap(shared_payload, shared_payload_map_bytes);
        }
        return 1;
    }

    std::fprintf(stderr, "[draft-ipc-daemon] ready gpu=%d ring_cap=%d\n",
                 draft_gpu, ring_cap);
    stream_status(stream_fd, 0);

    const int hidden = draft_weights.n_embd;
    const int q_len = draft_weights.block_size;
    const int n_tgt_layers = draft_weights.n_target_layers;
    StepGraph draft_sg;
    std::vector<float> noise_embed((size_t)hidden * q_len);
    std::vector<int32_t> pos_q(q_len);
    std::vector<int32_t> pos_k;
    std::vector<float> hidden_out((size_t)hidden * q_len);

    auto store_feature_slice = [&](int capture_idx,
                                   int start_pos,
                                   int n_tokens,
                                   const std::vector<float> & slice) -> bool {
        const size_t expected = (size_t)n_tokens * (size_t)hidden;
        if (slice.size() != expected) return false;
        const size_t dst_stride = feature_ring.target_feat->nb[1];
        const size_t slice_offset =
            (size_t)capture_idx * (size_t)hidden * sizeof(float);
        for (int i = 0; i < n_tokens; i++) {
            const int slot = (start_pos + i) % feature_ring.cap;
            const size_t dst_off = (size_t)slot * dst_stride + slice_offset;
            ggml_backend_tensor_set(feature_ring.target_feat,
                                    slice.data() + (size_t)i * hidden,
                                    dst_off,
                                    (size_t)hidden * sizeof(float));
        }
        ggml_backend_synchronize(backend);
        return true;
    };

    auto run_proposal = [&](int committed, int ctx_len) -> ProposalResult {
        int mirror_slot0 = 0;
        const bool use_mirror_view =
            draft_feature_mirror_can_view(feature_ring, committed, ctx_len, mirror_slot0);
        if (!build_draft_step(draft_sg, draft_weights, /*lm_head=*/nullptr, backend,
                              ctx_len, use_mirror_view ? &feature_ring : nullptr,
                              committed,
                              /*ctx_len_max=*/feature_ring.cap)) {
            std::fprintf(stderr, "[draft-ipc-daemon] draft build failed\n");
            stream_status(stream_fd, -1);
            return ProposalResult::CommandFailed;
        }
        if (!use_mirror_view &&
            !copy_feature_ring_range_to_tensor(feature_ring,
                                               draft_sg.target_hidden_cat,
                                               committed - ctx_len,
                                               ctx_len)) {
            std::fprintf(stderr, "[draft-ipc-daemon] feature copy failed\n");
            stream_status(stream_fd, -1);
            return ProposalResult::CommandFailed;
        }
        ggml_backend_tensor_set(draft_sg.inp_embed, noise_embed.data(), 0,
                                noise_embed.size() * sizeof(float));
        pos_k.resize((size_t)ctx_len + q_len);
        for (int i = 0; i < q_len; i++) pos_q[i] = ctx_len + i;
        for (int i = 0; i < ctx_len + q_len; i++) pos_k[i] = i;
        ggml_backend_tensor_set(draft_sg.positions, pos_q.data(), 0,
                                pos_q.size() * sizeof(int32_t));
        ggml_backend_tensor_set(draft_sg.positions_k, pos_k.data(), 0,
                                pos_k.size() * sizeof(int32_t));
        auto st = ggml_backend_graph_compute(backend, draft_sg.gf);
        if (st != GGML_STATUS_SUCCESS) {
            std::fprintf(stderr, "[draft-ipc-daemon] draft compute failed status=%d\n",
                         (int)st);
            stream_status(stream_fd, -1);
            return ProposalResult::CommandFailed;
        }
        ggml_backend_tensor_get(draft_sg.hidden_states, hidden_out.data(), 0,
                                hidden_out.size() * sizeof(float));
        if (!stream_status(stream_fd, 0) ||
            !write_exact_fd(stream_fd, hidden_out.data(),
                            hidden_out.size() * sizeof(float))) {
            std::fprintf(stderr, "[draft-ipc-daemon] stream write failed\n");
            return ProposalResult::StreamFailed;
        }
        return ProposalResult::Ok;
    };

    std::string line;
    while (std::getline(std::cin, line)) {
        std::istringstream iss(line);
        std::string cmd;
        iss >> cmd;
        if (cmd == "quit" || cmd == "exit") {
            break;
        }
        if (cmd == "feature_slice") {
            int capture_idx = -1;
            int start_pos = -1;
            int n_tokens = 0;
            iss >> capture_idx >> start_pos >> n_tokens;
            std::string path = read_line_tail(iss);
            if (capture_idx < 0 || capture_idx >= n_tgt_layers ||
                start_pos < 0 || n_tokens <= 0 || path.empty()) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad feature_slice: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            std::vector<float> slice((size_t)n_tokens * hidden);
            if (!read_binary_file_exact(path, slice.data(), slice.size() * sizeof(float))) {
                std::fprintf(stderr, "[draft-ipc-daemon] read feature_slice failed: %s\n",
                             path.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            if (!store_feature_slice(capture_idx, start_pos, n_tokens, slice)) {
                std::fprintf(stderr, "[draft-ipc-daemon] store feature_slice failed\n");
                stream_status(stream_fd, -1);
                continue;
            }
            stream_status(stream_fd, 0);
            continue;
        }
        if (cmd == "feature_slice_pipe") {
            int capture_idx = -1;
            int start_pos = -1;
            int n_tokens = 0;
            size_t bytes = 0;
            iss >> capture_idx >> start_pos >> n_tokens >> bytes;
            const size_t expected_bytes = (size_t)n_tokens * (size_t)hidden * sizeof(float);
            if (payload_fd < 0 || capture_idx < 0 || capture_idx >= n_tgt_layers ||
                start_pos < 0 || n_tokens <= 0 || bytes != expected_bytes) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad feature_slice_pipe: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            std::vector<float> slice(bytes / sizeof(float));
            if (!read_exact_fd(payload_fd, slice.data(), bytes)) {
                std::fprintf(stderr, "[draft-ipc-daemon] read feature_slice pipe failed\n");
                stream_status(stream_fd, -1);
                break;
            }
            if (!store_feature_slice(capture_idx, start_pos, n_tokens, slice)) {
                std::fprintf(stderr, "[draft-ipc-daemon] store feature_slice_pipe failed\n");
                stream_status(stream_fd, -1);
                continue;
            }
            stream_status(stream_fd, 0);
            continue;
        }
        if (cmd == "get_feature_range") {
            int start_pos = -1;
            int n_tokens = 0;
            iss >> start_pos >> n_tokens;
            if (start_pos < 0 || n_tokens <= 0 || n_tokens > feature_ring.cap) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad get_feature_range: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            const int fc_in = feature_ring.n_target_layers * feature_ring.hidden_size;
            const size_t row_bytes = (size_t)fc_in * sizeof(float);
            const size_t src_stride = feature_ring.target_feat->nb[1];
            // Stream in bounded chunks so daemon host memory stays O(chunk)
            // instead of O(n_tokens) — avoids large transient allocs / OOM
            // on long-context snapshot ranges. Total bytes on the wire are
            // unchanged, so the client read is identical.
            constexpr int kFeatRangeChunkTok = 256;
            const int chunk_tok = std::min(kFeatRangeChunkTok, n_tokens);
            std::vector<float> data((size_t)chunk_tok * (size_t)fc_in);
            if (!stream_status(stream_fd, 0)) {
                std::fprintf(stderr, "[draft-ipc-daemon] feature range stream failed\n");
                break;
            }
            bool stream_ok = true;
            for (int base = 0; base < n_tokens && stream_ok; base += chunk_tok) {
                const int nc = std::min(chunk_tok, n_tokens - base);
                for (int i = 0; i < nc; ++i) {
                    const int slot = (start_pos + base + i) % feature_ring.cap;
                    ggml_backend_tensor_get(feature_ring.target_feat,
                                            data.data() + (size_t)i * (size_t)fc_in,
                                            (size_t)slot * src_stride,
                                            row_bytes);
                }
                stream_ok = write_exact_fd(stream_fd, data.data(),
                                           (size_t)nc * row_bytes);
            }
            if (!stream_ok) {
                std::fprintf(stderr, "[draft-ipc-daemon] feature range stream failed\n");
                break;
            }
            continue;
        }
        if (cmd == "set_feature_range") {
            int start_pos = -1;
            int n_tokens = 0;
            iss >> start_pos >> n_tokens;
            std::string path = read_line_tail(iss);
            if (start_pos < 0 || n_tokens <= 0 || n_tokens > feature_ring.cap ||
                path.empty()) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad set_feature_range: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            const int fc_in = feature_ring.n_target_layers * feature_ring.hidden_size;
            const size_t row_bytes = (size_t)fc_in * sizeof(float);
            const size_t dst_stride = feature_ring.target_feat->nb[1];
            // Read + apply in bounded chunks so daemon host memory stays
            // O(chunk) instead of O(n_tokens) — avoids large transient allocs
            // / OOM on long-context snapshot restore.
            constexpr int kFeatRangeChunkTok = 256;
            const int chunk_tok = std::min(kFeatRangeChunkTok, n_tokens);
            std::ifstream fin(path, std::ios::binary);
            if (!fin) {
                std::fprintf(stderr, "[draft-ipc-daemon] read feature range failed: %s\n",
                             path.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            std::vector<float> data((size_t)chunk_tok * (size_t)fc_in);
            bool read_ok = true;
            for (int base = 0; base < n_tokens && read_ok; base += chunk_tok) {
                const int nc = std::min(chunk_tok, n_tokens - base);
                const std::streamsize want = (std::streamsize)((size_t)nc * row_bytes);
                fin.read(reinterpret_cast<char *>(data.data()), want);
                if (fin.gcount() != want) {
                    read_ok = false;
                    break;
                }
                for (int i = 0; i < nc; ++i) {
                    const int slot = (start_pos + base + i) % feature_ring.cap;
                    ggml_backend_tensor_set(feature_ring.target_feat,
                                            data.data() + (size_t)i * (size_t)fc_in,
                                            (size_t)slot * dst_stride,
                                            row_bytes);
                }
            }
            if (!read_ok) {
                std::fprintf(stderr, "[draft-ipc-daemon] read feature range failed: %s\n",
                             path.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            ggml_backend_synchronize(backend);
            stream_status(stream_fd, 0);
            continue;
        }
        if (cmd == "feature_slice_shared") {
            int capture_idx = -1;
            int start_pos = -1;
            int n_tokens = 0;
            size_t bytes = 0;
            uint64_t sequence = 0;
            iss >> capture_idx >> start_pos >> n_tokens >> bytes >> sequence;
            const size_t expected_bytes = (size_t)n_tokens * (size_t)hidden * sizeof(float);
            const auto * header =
                static_cast<const BackendIpcSharedPayloadHeader *>(shared_payload);
            if (!iss || sequence == 0 || !shared_payload || !shared_payload_data ||
                capture_idx < 0 || capture_idx >= n_tgt_layers ||
                start_pos < 0 || n_tokens <= 0 || bytes != expected_bytes ||
                !backend_ipc_payload_in_bounds(0, bytes, shared_payload_capacity) ||
                header->sequence != sequence || header->bytes != (uint64_t)bytes) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad feature_slice_shared: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            std::vector<float> slice(bytes / sizeof(float));
            std::memcpy(slice.data(), shared_payload_data, bytes);
            if (!store_feature_slice(capture_idx, start_pos, n_tokens, slice)) {
                std::fprintf(stderr, "[draft-ipc-daemon] store feature_slice_shared failed\n");
                stream_status(stream_fd, -1);
                continue;
            }
            stream_status(stream_fd, 0);
            continue;
        }
        if (cmd == "propose") {
            int committed = -1;
            int ctx_len = 0;
            iss >> committed >> ctx_len;
            std::string path = read_line_tail(iss);
            if (committed < 0 || ctx_len <= 0 || ctx_len > feature_ring.cap || path.empty()) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad propose: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            if (!read_binary_file_exact(path, noise_embed.data(),
                                        noise_embed.size() * sizeof(float))) {
                std::fprintf(stderr, "[draft-ipc-daemon] read noise failed: %s\n",
                             path.c_str());
                stream_status(stream_fd, -1);
                continue;
            }

            if (run_proposal(committed, ctx_len) == ProposalResult::StreamFailed) {
                break;
            }
            continue;
        }
        if (cmd == "propose_shared") {
            int committed = -1;
            int ctx_len = 0;
            size_t bytes = 0;
            uint64_t sequence = 0;
            iss >> committed >> ctx_len >> bytes >> sequence;
            const size_t expected_bytes = noise_embed.size() * sizeof(float);
            const auto * header =
                static_cast<const BackendIpcSharedPayloadHeader *>(shared_payload);
            if (!iss || sequence == 0 || !shared_payload || !shared_payload_data ||
                committed < 0 || ctx_len <= 0 || ctx_len > feature_ring.cap ||
                bytes != expected_bytes ||
                !backend_ipc_payload_in_bounds(0, bytes, shared_payload_capacity) ||
                header->sequence != sequence || header->bytes != (uint64_t)bytes) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad propose_shared: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            std::memcpy(noise_embed.data(), shared_payload_data, bytes);
            if (run_proposal(committed, ctx_len) == ProposalResult::StreamFailed) {
                break;
            }
            continue;
        }
        if (cmd == "propose_pipe") {
            int committed = -1;
            int ctx_len = 0;
            size_t bytes = 0;
            iss >> committed >> ctx_len >> bytes;
            const size_t expected_bytes = noise_embed.size() * sizeof(float);
            if (payload_fd < 0 || committed < 0 || ctx_len <= 0 ||
                ctx_len > feature_ring.cap || bytes != expected_bytes) {
                std::fprintf(stderr, "[draft-ipc-daemon] bad propose_pipe: %s\n",
                             line.c_str());
                stream_status(stream_fd, -1);
                continue;
            }
            if (!read_exact_fd(payload_fd, noise_embed.data(), bytes)) {
                std::fprintf(stderr, "[draft-ipc-daemon] read noise pipe failed\n");
                stream_status(stream_fd, -1);
                break;
            }
            if (run_proposal(committed, ctx_len) == ProposalResult::StreamFailed) {
                break;
            }
            continue;
        }
        std::fprintf(stderr, "[draft-ipc-daemon] unknown command: %s\n", line.c_str());
        stream_status(stream_fd, -1);
    }

    step_graph_destroy(draft_sg);
    draft_feature_mirror_free(feature_ring);
    free_draft_weights(draft_weights);
    ggml_backend_free(backend);
    if (shared_payload && shared_payload != MAP_FAILED) {
        ::munmap(shared_payload, shared_payload_map_bytes);
    }
    std::fprintf(stderr, "[draft-ipc-daemon] stopped\n");
    return 0;
#endif
}

} // namespace dflash::common

// dflash_feature_ring.cpp — implementation for common DFlash feature ring.

#include "dflash_feature_ring.h"
#include "peer_access.h"

#include "ggml.h"

// ggml_get_to_fp32_cuda is not in any public header — it lives in
// ggml-cuda/convert.cuh. Declare the typedef + extern here so we can link
// against it from this TU.
using to_fp32_cuda_t = void (*)(const void *, float *, int64_t, cudaStream_t);
extern "C++" to_fp32_cuda_t ggml_get_to_fp32_cuda(ggml_type type);

#include <algorithm>
#include <cstdlib>
#include <cstring>
#include <cstdio>
#include <vector>

#include "gpu_runtime_compat.h"

namespace dflash::common {

// ── internal helpers ────────────────────────────────────────────

static bool ensure_staging(DraftFeatureMirror & mirror, size_t bytes) {
    if (bytes <= mirror.staging_bytes) return true;
    cudaError_t err = cudaSetDevice(mirror.device);
    if (err != cudaSuccess) return false;
    if (mirror.staging) {
        err = cudaFree(mirror.staging);
        if (err != cudaSuccess) return false;
        mirror.staging = nullptr;
        mirror.staging_bytes = 0;
    }
    err = cudaMalloc(&mirror.staging, bytes);
    if (err != cudaSuccess) return false;
    mirror.staging_bytes = bytes;
    return true;
}

static ggml_type parse_feature_dtype() {
    const char * s = std::getenv("DFLASH_FEATURE_DTYPE");
    if (!s || !s[0] || std::strcmp(s, "f32") == 0 || std::strcmp(s, "F32") == 0) {
        return GGML_TYPE_F32;
    }
    if (std::strcmp(s, "f16") == 0 || std::strcmp(s, "F16") == 0) {
        return GGML_TYPE_F16;
    }
    if (std::strcmp(s, "bf16") == 0 || std::strcmp(s, "BF16") == 0) {
        return GGML_TYPE_BF16;
    }
    if (std::strcmp(s, "q8_0") == 0 || std::strcmp(s, "Q8_0") == 0 ||
        std::strcmp(s, "q8") == 0 || std::strcmp(s, "Q8") == 0) {
        return GGML_TYPE_Q8_0;
    }
    std::fprintf(stderr, "[dflash-feature] ignoring unsupported DFLASH_FEATURE_DTYPE=%s\n", s);
    return GGML_TYPE_F32;
}

static bool check_feature_width_compatible(ggml_type type, int width) {
    const int64_t blck = ggml_blck_size(type);
    return blck > 0 && width > 0 && width % blck == 0;
}

static bool quantize_host_f32_to_feature_type(ggml_type type,
                                              const float * src,
                                              void * dst,
                                              size_t elems) {
    const auto * traits = ggml_get_type_traits(type);
    if (!traits || !traits->from_float_ref) return false;
    if (traits->blck_size <= 0 || elems % (size_t)traits->blck_size != 0) return false;
    traits->from_float_ref(src, dst, (int64_t)elems);
    return true;
}

static bool dequantize_feature_type_to_host_f32(ggml_type type,
                                                const void * src,
                                                float * dst,
                                                size_t elems) {
    const auto * traits = ggml_get_type_traits(type);
    if (!traits || !traits->to_float) return false;
    if (traits->blck_size <= 0 || elems % (size_t)traits->blck_size != 0) return false;
    traits->to_float(src, dst, (int64_t)elems);
    return true;
}

static bool host_f32_to_feature_row(ggml_type type,
                                    const float * src,
                                    void * dst,
                                    size_t elems) {
    if (type == GGML_TYPE_F32) {
        std::memcpy(dst, src, elems * sizeof(float));
        return true;
    }
    if (type == GGML_TYPE_F16) {
        ggml_fp32_to_fp16_row(src, (ggml_fp16_t *)dst, (int64_t)elems);
        return true;
    }
    if (type == GGML_TYPE_BF16) {
        ggml_fp32_to_bf16_row(src, (ggml_bf16_t *)dst, (int64_t)elems);
        return true;
    }
    return quantize_host_f32_to_feature_type(type, src, dst, elems);
}

static bool feature_row_to_host_f32(ggml_type type,
                                    const void * src,
                                    float * dst,
                                    size_t elems) {
    if (type == GGML_TYPE_F32) {
        std::memcpy(dst, src, elems * sizeof(float));
        return true;
    }
    if (type == GGML_TYPE_F16) {
        ggml_fp16_to_fp32_row((const ggml_fp16_t *)src, dst, (int64_t)elems);
        return true;
    }
    if (type == GGML_TYPE_BF16) {
        ggml_bf16_to_fp32_row((const ggml_bf16_t *)src, dst, (int64_t)elems);
        return true;
    }
    return dequantize_feature_type_to_host_f32(type, src, dst, elems);
}

static bool convert_device_f32_to_feature_type(DraftFeatureMirror & mirror,
                                               const void * src,
                                               int src_device,
                                               void * dst,
                                               size_t elems) {
    if (mirror.storage_type == GGML_TYPE_F32) {
        return copy_peer_async(dst, mirror.device, src, src_device,
                               elems * sizeof(float));
    }

    std::vector<float> host(elems);
    cudaError_t err = cudaSetDevice(src_device);
    if (err != cudaSuccess) return false;
    err = cudaMemcpy(host.data(), src, elems * sizeof(float),
                     cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) return false;

    const size_t row_bytes = ggml_row_size(mirror.storage_type, (int64_t)elems);
    std::vector<uint8_t> tmp(row_bytes);
    if (!host_f32_to_feature_row(mirror.storage_type, host.data(), tmp.data(), elems)) {
        return false;
    }
    ggml_backend_tensor_set(mirror.target_feat, tmp.data(),
                            (size_t)((char *)dst - (char *)mirror.target_feat->data),
                            row_bytes);
    return true;
}

static bool convert_bf16_feature_to_storage(DraftFeatureMirror & mirror,
                                            const void * src,
                                            int src_device,
                                            void * dst,
                                            size_t elems) {
    if (mirror.storage_type == GGML_TYPE_BF16) {
        return copy_peer_async(dst, mirror.device, src, src_device,
                               elems * sizeof(ggml_bf16_t));
    }

    const size_t blck = (size_t)ggml_blck_size(mirror.storage_type);
    if (blck == 0 || elems % blck != 0) return false;

    constexpr size_t max_chunk_bytes = 4u * 1024u * 1024u;
    const size_t max_chunk_elems =
        std::max(blck, (max_chunk_bytes / sizeof(float) / blck) * blck);
    const size_t dst_offset = (size_t)((char *)dst - (char *)mirror.target_feat->data);

    cudaError_t err = cudaSetDevice(src_device);
    if (err != cudaSuccess) return false;

    size_t done = 0;
    size_t dst_bytes_done = 0;
    while (done < elems) {
        size_t chunk = std::min(elems - done, max_chunk_elems);
        chunk = (chunk / blck) * blck;
        if (chunk == 0) return false;

        std::vector<ggml_bf16_t> bf16_host(chunk);
        err = cudaMemcpy(bf16_host.data(),
                         (const char *)src + done * sizeof(ggml_bf16_t),
                         chunk * sizeof(ggml_bf16_t),
                         cudaMemcpyDeviceToHost);
        if (err != cudaSuccess) return false;

        std::vector<float> host(chunk);
        ggml_bf16_to_fp32_row(bf16_host.data(), host.data(), (int64_t)chunk);

        const size_t chunk_bytes = ggml_row_size(mirror.storage_type, (int64_t)chunk);
        std::vector<uint8_t> tmp(chunk_bytes);
        if (!host_f32_to_feature_row(mirror.storage_type, host.data(), tmp.data(), chunk)) {
            return false;
        }
        ggml_backend_tensor_set(mirror.target_feat, tmp.data(),
                                dst_offset + dst_bytes_done, chunk_bytes);
        done += chunk;
        dst_bytes_done += chunk_bytes;
    }
    return true;
}

static bool copy_feature_to_f32(DraftFeatureMirror & mirror,
                                const void * src,
                                int src_device,
                                float * dst,
                                size_t elems) {
    if (mirror.storage_type == GGML_TYPE_F32) {
        return copy_peer_async(dst, mirror.device, src, src_device,
                               elems * sizeof(float));
    }
    auto to_f32 = ggml_get_to_fp32_cuda(mirror.storage_type);
    if (!to_f32) return false;
    const size_t src_bytes = ggml_row_size(mirror.storage_type, (int64_t)elems);
    if (src_device != mirror.device) {
        if (!ensure_staging(mirror, src_bytes)) return false;
        if (!copy_peer_async(mirror.staging, mirror.device, src, src_device,
                             src_bytes)) {
            return false;
        }
        src = mirror.staging;
    }
    cudaError_t err = cudaSetDevice(mirror.device);
    if (err != cudaSuccess) return false;
    to_f32(src, dst, (int64_t)elems, nullptr);
    return cudaGetLastError() == cudaSuccess;
}

// ── public API ──────────────────────────────────────────────────

void draft_feature_mirror_free(DraftFeatureMirror & mirror) {
    if (mirror.staging) {
        (void)cudaSetDevice(mirror.device);
        (void)cudaFree(mirror.staging);
        mirror.staging = nullptr;
        mirror.staging_bytes = 0;
    }
    if (mirror.buf) {
        ggml_backend_buffer_free(mirror.buf);
        mirror.buf = nullptr;
    }
    if (mirror.ctx) {
        ggml_free(mirror.ctx);
        mirror.ctx = nullptr;
    }
    mirror.target_feat = nullptr;
    mirror.device = 0;
    mirror.target_device = 0;
    mirror.cap = 0;
    mirror.storage_type = GGML_TYPE_F32;
}

bool draft_feature_mirror_init(DraftFeatureMirror & mirror,
                               ggml_backend_t backend,
                               int device,
                               int target_device,
                               int cap,
                               int n_target_layers,
                               int hidden_size) {
    draft_feature_mirror_free(mirror);
    if (cap <= 0 || n_target_layers <= 0 || hidden_size <= 0) return false;
    mirror.device = device;
    mirror.target_device = target_device;
    mirror.n_target_layers = n_target_layers;
    mirror.hidden_size = hidden_size;
    mirror.storage_type = parse_feature_dtype();
    if (!check_feature_width_compatible(mirror.storage_type, hidden_size) ||
        !check_feature_width_compatible(mirror.storage_type, n_target_layers * hidden_size)) {
        std::fprintf(stderr,
                     "[dflash-feature] unsupported mirror dtype=%s for hidden=%d layers=%d\n",
                     ggml_type_name(mirror.storage_type), hidden_size, n_target_layers);
        mirror.storage_type = GGML_TYPE_F32;
    }

    ggml_init_params ip{};
    ip.mem_size = ggml_tensor_overhead() * 4 + 16 * 1024;
    ip.mem_buffer = nullptr;
    ip.no_alloc = true;
    mirror.ctx = ggml_init(ip);
    if (!mirror.ctx) return false;

    const int fc_in = n_target_layers * hidden_size;
    mirror.target_feat = ggml_new_tensor_2d(mirror.ctx, mirror.storage_type, fc_in, cap);
    ggml_set_name(mirror.target_feat, "draft_target_feat_mirror");
    mirror.buf = ggml_backend_alloc_ctx_tensors(mirror.ctx, backend);
    if (!mirror.buf) {
        draft_feature_mirror_free(mirror);
        return false;
    }
    const size_t bytes = ggml_nbytes(mirror.target_feat);
    cudaError_t err = cudaSetDevice(device);
    if (err != cudaSuccess) {
        draft_feature_mirror_free(mirror);
        return false;
    }
    err = cudaMemset(mirror.target_feat->data, 0, bytes);
    if (err != cudaSuccess) {
        draft_feature_mirror_free(mirror);
        return false;
    }
    mirror.cap = cap;
    std::fprintf(stderr, "[dflash-feature] mirror dtype=%s cap=%d fc_in=%d\n",
                 ggml_type_name(mirror.storage_type), cap, fc_in);
    return true;
}

bool draft_feature_mirror_can_view(const DraftFeatureMirror & mirror,
                                   int committed,
                                   int ctx_len,
                                   int & slot0) {
    if (!mirror.target_feat || mirror.cap <= 0) return false;
    if (ctx_len <= 0 || ctx_len > mirror.cap || committed < ctx_len) return false;
    const int start = committed - ctx_len;
    slot0 = start % mirror.cap;
    return mirror.storage_type == GGML_TYPE_F32 && slot0 + ctx_len <= mirror.cap;
}

bool draft_feature_mirror_sync_range(const ggml_tensor * src_target_feat,
                                     int src_cap,
                                     DraftFeatureMirror & mirror,
                                     int start_pos,
                                     int n_tokens) {
    if (!src_target_feat || !mirror.target_feat || mirror.cap <= 0 || src_cap <= 0) return false;
    if (n_tokens <= 0) return true;
    if (n_tokens > mirror.cap) return false;

    const int fc_in = mirror.n_target_layers * mirror.hidden_size;
    const size_t src_stride = src_target_feat->nb[1];
    const size_t dst_stride = mirror.target_feat->nb[1];

    int done = 0;
    while (done < n_tokens) {
        const int src_slot = (start_pos + done) % src_cap;
        const int dst_slot = (start_pos + done) % mirror.cap;
        const int src_run = src_cap - src_slot;
        const int dst_run = mirror.cap - dst_slot;
        const int run = std::min(n_tokens - done, std::min(src_run, dst_run));
        const size_t elems = (size_t)run * (size_t)fc_in;
        const void * src =
            (const char *)src_target_feat->data + (size_t)src_slot * src_stride;
        void * dst =
            (char *)mirror.target_feat->data + (size_t)dst_slot * dst_stride;
        if (!convert_bf16_feature_to_storage(mirror, src, mirror.target_device, dst, elems)) {
            return false;
        }
        cudaError_t err = cudaGetLastError();
        if (err != cudaSuccess) return false;
        done += run;
    }
    return cudaDeviceSynchronize() == cudaSuccess;
}

bool draft_feature_mirror_sync_tail(const ggml_tensor * src_target_feat,
                                    int src_cap,
                                    DraftFeatureMirror & mirror,
                                    int committed) {
    if (!mirror.target_feat || committed <= 0) return true;
    const int n = std::min(committed, mirror.cap);
    return draft_feature_mirror_sync_range(src_target_feat, src_cap, mirror,
                                           committed - n, n);
}

// ── Ring ↔ tensor copy helpers ──────────────────────────────────

bool copy_capture_slice_to_draft_ring(
    DraftFeatureMirror & feature_ring,
    int capture_idx,
    const ggml_tensor * act_out,
    int src_device,
    int chunk_start,
    int start_pos,
    int n_tokens) {
    if (!feature_ring.target_feat || n_tokens <= 0) return true;
    if (capture_idx < 0 || capture_idx >= feature_ring.n_target_layers ||
        start_pos < 0 || feature_ring.cap <= 0 ||
        feature_ring.hidden_size <= 0) {
        return false;
    }
    const int hidden = feature_ring.hidden_size;
    const size_t dst_stride = feature_ring.target_feat->nb[1];
    const size_t src_stride = act_out->nb[1];
    const size_t row_elems = (size_t)hidden;
    for (int i = 0; i < n_tokens; i++) {
        const int slot = (start_pos + i) % feature_ring.cap;
        const void * src = (const char *)act_out->data +
            (size_t)(chunk_start + i) * src_stride;
        void * dst = (char *)feature_ring.target_feat->data +
            (size_t)slot * dst_stride +
            (size_t)capture_idx * ggml_row_size(feature_ring.storage_type, hidden);
        if (!convert_device_f32_to_feature_type(feature_ring, src, src_device, dst, row_elems)) {
            return false;
        }
    }
    return cudaDeviceSynchronize() == cudaSuccess;
}

bool copy_host_capture_slice_to_draft_ring(
    DraftFeatureMirror & feature_ring,
    int capture_idx,
    int start_pos,
    int n_tokens,
    const float * host,
    size_t host_elems) {
    if (!feature_ring.target_feat || n_tokens <= 0) return true;
    if (capture_idx < 0 || capture_idx >= feature_ring.n_target_layers ||
        start_pos < 0 || !host || feature_ring.cap <= 0 ||
        feature_ring.hidden_size <= 0) {
        return false;
    }
    const int hidden = feature_ring.hidden_size;
    const size_t expected = (size_t)n_tokens * (size_t)hidden;
    if (host_elems != expected) return false;
    const size_t dst_stride = feature_ring.target_feat->nb[1];
    const size_t row_bytes = (size_t)hidden * sizeof(float);
    for (int i = 0; i < n_tokens; ++i) {
        const int slot = (start_pos + i) % feature_ring.cap;
        const float * src = host + (size_t)i * (size_t)hidden;
        const size_t dst_offset =
            (size_t)slot * dst_stride +
            (size_t)capture_idx * (size_t)hidden * sizeof(float);
        ggml_backend_tensor_set(feature_ring.target_feat, src, dst_offset, row_bytes);
    }
    return true;
}

bool copy_feature_ring_range_to_tensor(
    const DraftFeatureMirror & feature_ring,
    ggml_tensor * dst,
    int start_pos,
    int n_tokens) {
    if (!feature_ring.target_feat || !dst || feature_ring.cap <= 0) return false;
    if (n_tokens <= 0 || n_tokens > feature_ring.cap) return false;

    const int fc_in = feature_ring.n_target_layers * feature_ring.hidden_size;
    const size_t row_bytes = (size_t)fc_in * sizeof(float);
    const size_t src_stride = feature_ring.target_feat->nb[1];
    const size_t dst_stride = dst->nb[1];
    int done = 0;
    while (done < n_tokens) {
        const int slot = (start_pos + done) % feature_ring.cap;
        const int run = std::min(n_tokens - done, feature_ring.cap - slot);
        const char * src_base =
            (const char *)feature_ring.target_feat->data + (size_t)slot * src_stride;
        char * dst_base = (char *)dst->data + (size_t)done * dst_stride;
        if (feature_ring.storage_type == GGML_TYPE_F32 &&
            src_stride == row_bytes && dst_stride == row_bytes) {
            if (!copy_peer_async(dst_base, feature_ring.device,
                                 src_base, feature_ring.device,
                                 row_bytes * (size_t)run)) {
                return false;
            }
        } else {
            for (int i = 0; i < run; i++) {
                if (!copy_feature_to_f32(
                        const_cast<DraftFeatureMirror &>(feature_ring),
                        src_base + (size_t)i * src_stride,
                        feature_ring.device,
                        (float *)(dst_base + (size_t)i * dst_stride),
                        (size_t)fc_in)) {
                    return false;
                }
            }
        }
        done += run;
    }
    return cudaDeviceSynchronize() == cudaSuccess;
}

bool copy_feature_ring_range_to_host_f32(
    const DraftFeatureMirror & feature_ring,
    int start_pos,
    int n_tokens,
    std::vector<float> & out) {
    if (!feature_ring.target_feat || feature_ring.cap <= 0) return false;
    if (n_tokens <= 0 || n_tokens > feature_ring.cap) return false;

    const int fc_in = feature_ring.n_target_layers * feature_ring.hidden_size;
    const size_t row_bytes = ggml_row_size(feature_ring.storage_type, fc_in);
    const size_t src_stride = feature_ring.target_feat->nb[1];
    std::vector<uint8_t> row(row_bytes);
    out.resize((size_t)n_tokens * (size_t)fc_in);

    for (int i = 0; i < n_tokens; ++i) {
        const int slot = (start_pos + i) % feature_ring.cap;
        ggml_backend_tensor_get(feature_ring.target_feat, row.data(),
                                (size_t)slot * src_stride, row_bytes);
        float * dst = out.data() + (size_t)i * (size_t)fc_in;
        if (!feature_row_to_host_f32(feature_ring.storage_type, row.data(), dst, fc_in)) {
            return false;
        }
    }
    return true;
}

bool copy_host_f32_to_feature_ring_range(
    DraftFeatureMirror & feature_ring,
    int start_pos,
    int n_tokens,
    const std::vector<float> & src) {
    if (!feature_ring.target_feat || feature_ring.cap <= 0) return false;
    if (n_tokens <= 0 || n_tokens > feature_ring.cap) return false;

    const int fc_in = feature_ring.n_target_layers * feature_ring.hidden_size;
    if (src.size() < (size_t)n_tokens * (size_t)fc_in) return false;
    const size_t dst_stride = feature_ring.target_feat->nb[1];
    const size_t row_bytes = ggml_row_size(feature_ring.storage_type, fc_in);
    std::vector<uint8_t> row(row_bytes);

    for (int i = 0; i < n_tokens; ++i) {
        const float * src_row = src.data() + (size_t)i * (size_t)fc_in;
        if (!host_f32_to_feature_row(feature_ring.storage_type, src_row, row.data(), fc_in)) {
            return false;
        }
        const int slot = (start_pos + i) % feature_ring.cap;
        ggml_backend_tensor_set(feature_ring.target_feat, row.data(),
                                (size_t)slot * dst_stride, row_bytes);
    }
    return true;
}

